INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_013','数学竞赛成绩出啦','非数A类一等奖\n以及，南京大牌档的冬季新品超级好吃，强推这个豆角焖饼','place_001',2,6,4.0,2,'["uploads/images/20250529_014831_1__.jpg"]',NULL,'["竞赛"]',0,'2025-05-29 01:48:34');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_012','是北邮的超前点映！','本来想签个到就溜走，但是雄狮少年2画面很好很好非常好，还有一些熟悉的方言倍感亲切，把我硬控到九点。\n毛不易的《无名的人》更是点睛之笔！\n这下子六级要寄寄了😭','place_001',2,31,3.8,2,NULL,'["uploads/videos/20250529_003110_1__.mp4", "uploads/videos/20250529_003116_2__.mp4", "uploads/videos/20250529_003126_3__.mp4", "uploads/videos/20250529_003138_4__.mp4"]','["雄狮少年"]',0,'2025-05-29 00:31:42');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_011','熬穿了','不想熬夜','place_001',2,4,2.2,2,'["uploads/images/20250529_002822_2__.jpg", "uploads/images/20250529_002827_1__.jpg"]',NULL,'["计网课设我恨你"]',0,'2025-05-29 00:28:32');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_010','国奖答辩顺利~','本来特别焦虑😟\n没想到小姐姐泥背稿子演讲起来也语速飞快，泥没救了）\n大一也没忙啥科研竞赛，忙活的也没有啥好结果，就在自己热爱的绘画啊体育啊志愿啊等等方面玩耍了，感觉不够出色哪配国奖。\n不过也多亏这些，智育虽然是4/475，但综测排到了第一','place_001',2,1,5,1,'["uploads/images/20250529_002445_1__.jpg", "uploads/images/20250529_002452_2__.jpg"]',NULL,'["国奖答辩", "北邮计算机"]',0,'2025-05-29 00:24:53');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_008','通宵与破晓','数学建模你把我害惨了','place_001',2,2,4.5,2,'["uploads/images/20250529_002245_1__.jpg", "uploads/images/20250529_002252_2__.jpg"]',NULL,'["通宵"]',0,'2025-05-29 00:22:53');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_007','给室友第一次调酒','825第一次外出团建！\n好吃！\n#凑一起更嗨棒','place_001',1,3,3,1,'["uploads/images/20250529_001655_1_limpid_.jpg", "uploads/images/20250529_001701_2_limpid_.jpg"]',NULL,'["宿舍"]',0,'2025-05-29 00:17:03');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_006','算法竞赛混子如何出题','大家好 我是 limpid！\n\t\n收到学校任务要出 ccpc 网络赛的题目 还要出两个！！！由于 limpid 比较摆 训练不积极 之前题目的idea 全用过了 于是一度陷于自闭之中qaq\n\t\n在军训时候过于无聊于是想了想子序列的相关知识 发现算子序列出现次数的时候可以矩阵乘法 于是 D 题就产生了！看了#解密 那个电影加上学完了 #transformer 后觉得 encode decode两个过程很酷题目就写成这样了。\n\t\nE 题想法是因为 Trie 树开多大空间还没有想过 加上自己在看随机过程的书（但最后选择了概率统计因为随机过程只开一个班！！！）于是在军训的时候想了一下觉得很简单就出了此题（果然是混子）\n\t\n本身以为 D 很有趣但后面发现暴力 dp 也可以qaq\n\t\n没想到最后 E 题通过人数比 D 还少。\n\t\n希望大家喜欢这场比赛！\n\t\nlimpid 实在不会出题了qaq\n','place_001',1,1,3,1,'["uploads/images/20250529_001504_1_limpid_.jpg", "uploads/images/20250529_001508_2_limpid_.jpg", "uploads/images/20250529_001511_3_limpid_.jpg"]',NULL,'["算法竞赛"]',0,'2025-05-29 00:15:12');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_005','不做ddl战士','作业要提前做！！！\n作业要提前做！！！\n作业要提前做！！！\n否则概率论需要写 30 道积分题！！！！！','place_001',1,1,2.5,2,'["uploads/images/20250529_000751_DDL_1_limpid_.jpg"]',NULL,'["期末考试"]',0,'2025-05-29 00:07:54');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_004','不做ddl战士2','ddl是第一生产力','place_001',1,4,2,1,'["uploads/images/20250529_000617_ddl2_1_limpid_.jpg"]',NULL,'["期末考试"]',0,'2025-05-29 00:06:24');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_003','双金！','在外面玩了一周！CCPC和ICPC都金啦！\n','place_001',1,3,5,1,'["uploads/images/20250529_000457_1_limpid_.jpg", "uploads/images/20250529_000501_2_limpid_.jpg"]',NULL,'["算法竞赛"]',0,'2025-05-29 00:05:02');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_002','不做ddl战士3','期末该怎么办 期末该怎么办 期末该怎么办\n什么也不会就只剩3周了\n该咋办 该咋办 该咋办','place_001',1,7,3.5,2,'["uploads/images/20250529_000237_ddl3_1_limpid_.jpg"]',NULL,'["期末考试"]',0,'2025-05-29 00:02:39');
INSERT INTO `travel_diary` (`id`,`title`,`content`,`place_id`,`author_id`,`click_count`,`rating`,`rating_count`,`images`,`videos`,`tags`,`deleted`,`created_at`) VALUES ('diary_001','北邮校园调酒！','在正经学校里做不正经的事！👀\n码农做出来的酒会是什么味道呢？🤔\n今晚九点麦麦门口不见不散！🥳\n\t\n因摊主个人原因，小摊定点不定时刷新，敬请关注后续动态！','place_001',1,27,3.7,6,'["uploads/images/20250528_235635_1__.jpg"]',NULL,'["美食", "学术"]',0,'2025-05-28 23:57:01');
